from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

# Replace with your Ethereum node URL
WEB3_NODE_URL = 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'
web3 = Web3(Web3.HTTPProvider(WEB3_NODE_URL))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    message = data['message']
    signature = data['signature']
    address = data['address']

    if not web3.isConnected():
        return jsonify({'error': 'Web3 node is not connected'}), 500

    try:
        recovered_address = web3.eth.account.recover_message(message, signature=signature)
        if recovered_address.lower() == address.lower():
            return jsonify({'authenticated': True}), 200
        else:
            return jsonify({'authenticated': False}), 401
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)